     1|/**
     2| * IVX Safe Render Environment-Variable Merge (Phase 1 — 2026-07-16).
     3| *
     4| * Problem: Render's PUT /v1/services/{id}/env-vars endpoint REPLACES the entire
     5| * variable set. A naive update that sends only the new/changed variables wipes
     6| * every other variable on the service — including secrets like OPENAI_API_KEY,
     7| * SUPABASE_SERVICE_ROLE_KEY, etc.
     8| *
     9| * Solution: This module implements a safe read-merge-write-validate workflow:
    10| *   1. Read the full existing variable set (GET).
    11| *   2. Abort if the read fails.
    12| *   3. Merge only the intended additions/updates into the existing set.
    13| *   4. Submit the complete merged set (PUT).
    14| *   5. Read the variables again (GET).
    15| *   6. Confirm every required variable remains present and non-empty.
    16| *   7. Abort if post-write validation detects a missing variable.
    17| *   8. Never log secret values.
    18| *   9. Return a trace ID and rollback instructions.
    19| */
    20|import { randomUUID } from 'node:crypto';
    21|
    22|const RENDER_API_BASE_URL = 'https://api.render.com/v1';
    23|
    24|// In-memory merge lock to serialize concurrent env-var updates per service.
    25|// Without this, two concurrent merges can race: both read the same base set,
    26|// each adds only its own variable, and the second PUT overwrites the first's
    27|// addition. The lock ensures the second merge reads AFTER the first writes.
    28|const mergeLocks = new Map<string, Promise<void>>();
    29|
    30|export type RenderEnvVar = {
    31|  key: string;
    32|  value: string;
    33|};
    34|
    35|export type RenderEnvVarResponse = {
    36|  envVar: RenderEnvVar;
    37|};
    38|
    39|export type SafeMergeResult = {
    40|  traceId: string;
    41|  ok: boolean;
    42|  variablesBefore: number;
    43|  variablesAfter: number;
    44|  added: string[];
    45|  updated: string[];
    46|  preserved: string[];
    47|  missingAfterValidation: string[];
    48|  rollbackInstructions: string;
    49|  error: string | null;
    50|  secretValuesReturned: false;
    51|};
    52|
    53|export type SafeMergeInput = {
    54|  renderApiKey: string;
    55|  serviceId: string;
    56|  /** Variables to add or update (merged into existing set). */
    57|  updates: Record<string, string>;
    58|  /** Variables that MUST be present and non-empty after the write. */
    59|  requiredKeys?: string[];
    60|  /** Injectable fetch for testing. */
    61|  fetchImpl?: typeof fetch;
    62|};
    63|
    64|function redactValue(value: string): string {
    65|  if (!value) return '';
    66|  return value.length > 4 ? `${value.slice(0, 2)}…${value.slice(-2)}` : '****';
    67|}
    68|
    69|function renderHeaders(apiKey: string): Record<string, string> {
    70|  return {
    71|    Accept: 'application/json',
    72|    'Content-Type': 'application/json',
    73|    Authorization: `Bearer ${apiKey}`,
    74|  };
    75|}
    76|
    77|/**
    78| * Read the full existing Render env-var set for a service.
    79| * Returns a map of key → value. Throws on failure.
    80| */
    81|export async function readRenderEnvVars(
    82|  serviceId: string,
    83|  apiKey: string,
    84|  fetchImpl: typeof fetch = fetch,
    85|): Promise<Map<string, string>> {
    86|  const url = `${RENDER_API_BASE_URL}/services/${encodeURIComponent(serviceId)}/env-vars`;
    87|  const response = await fetchImpl(url, {
    88|    method: 'GET',
    89|    headers: renderHeaders(apiKey),
    90|  });
    91|  if (!response.ok) {
    92|    const text = await response.text().catch(() => '');
    93|    throw new Error(
    94|      `Render env-vars GET failed (HTTP ${response.status}): ${text.slice(0, 300)}`,
    95|    );
    96|  }
    97|  const data = (await response.json()) as RenderEnvVarResponse[];
    98|  const map = new Map<string, string>();
    99|  if (Array.isArray(data)) {
   100|    for (const item of data) {
   101|      const ev = item?.envVar ?? item;
   102|      if (ev && typeof ev.key === 'string') {
   103|        map.set(ev.key, typeof ev.value === 'string' ? ev.value : '');
   104|      }
   105|    }
   106|  }
   107|  return map;
   108|}
   109|
   110|/**
   111| * Write the full env-var set to Render (PUT replaces all).
   112| * Returns the written keys. Throws on failure.
   113| */
   114|export async function writeRenderEnvVars(
   115|  serviceId: string,
   116|  apiKey: string,
   117|  vars: Map<string, string>,
   118|  fetchImpl: typeof fetch = fetch,
   119|): Promise<string[]> {
   120|  const url = `${RENDER_API_BASE_URL}/services/${encodeURIComponent(serviceId)}/env-vars`;
   121|  const body = Array.from(vars.entries()).map(([key, value]) => ({ key, value }));
   122|  const response = await fetchImpl(url, {
   123|    method: 'PUT',
   124|    headers: renderHeaders(apiKey),
   125|    body: JSON.stringify(body),
   126|  });
   127|  if (!response.ok) {
   128|    const text = await response.text().catch(() => '');
   129|    throw new Error(
   130|      `Render env-vars PUT failed (HTTP ${response.status}): ${text.slice(0, 300)}`,
   131|    );
   132|  }
   133|  return Array.from(vars.keys());
   134|}
   135|
   136|/**
   137| * Safe merge: read → merge → write → validate.
   138| * Never overwrites existing variables that aren't in the update set.
   139| * Returns a trace ID and rollback instructions for audit.
   140| */
   141|export async function safeMergeRenderEnvVars(
   142|  input: SafeMergeInput,
   143|): Promise<SafeMergeResult> {
   144|  const traceId = `ivx-env-merge-${randomUUID()}`;
   145|  const fetchImpl = input.fetchImpl ?? fetch;
   146|  const requiredKeys = input.requiredKeys ?? [];
   147|
   148|  // Serialize concurrent merges per service to prevent race conditions.
   149|  const serviceId = input.serviceId;
   150|  const prevLock = mergeLocks.get(serviceId) ?? Promise.resolve();
   151|  let resolveLock: () => void = () => {};
   152|  const thisLock = new Promise<void>((resolve) => { resolveLock = resolve; });
   153|  const chainedLock = prevLock.then(() => thisLock);
   154|  mergeLocks.set(serviceId, chainedLock);
   155|  await prevLock;
   156|  try {
   157|    return await safeMergeRenderEnvVarsInner(input, traceId, fetchImpl, requiredKeys);
   158|  } finally {
   159|    resolveLock();
   160|    if (mergeLocks.get(serviceId) === chainedLock) {
   161|      mergeLocks.delete(serviceId);
   162|    }
   163|  }
   164|}
   165|
   166|async function safeMergeRenderEnvVarsInner(
   167|  input: SafeMergeInput,
   168|  traceId: string,
   169|  fetchImpl: typeof fetch,
   170|  requiredKeys: string[],
   171|): Promise<SafeMergeResult> {
   172|
   173|  // Step 1: Read existing variables. Abort if read fails.
   174|  let existing: Map<string, string>;
   175|  try {
   176|    existing = await readRenderEnvVars(
   177|      input.serviceId,
   178|      input.renderApiKey,
   179|      fetchImpl,
   180|    );
   181|  } catch (error) {
   182|    return {
   183|      traceId,
   184|      ok: false,
   185|      variablesBefore: 0,
   186|      variablesAfter: 0,
   187|      added: [],
   188|      updated: [],
   189|      preserved: [],
   190|      missingAfterValidation: [],
   191|      rollbackInstructions: 'No changes were made. Fix the Render API read error and retry.',
   192|      error: error instanceof Error ? error.message : 'Unknown error during env-var read.',
   193|      secretValuesReturned: false,
   194|    };
   195|  }
   196|
   197|  const variablesBefore = existing.size;
   198|  const added: string[] = [];
   199|  const updated: string[] = [];
   200|
   201|  // Step 2: Merge updates into existing set.
   202|  const merged = new Map(existing);
   203|  for (const [key, value] of Object.entries(input.updates)) {
   204|    if (existing.has(key)) {
   205|      updated.push(key);
   206|    } else {
   207|      added.push(key);
   208|    }
   209|    merged.set(key, value);
   210|  }
   211|
   212|  const preserved = Array.from(existing.keys()).filter(
   213|    (k) => !input.updates.hasOwnProperty(k),
   214|  );
   215|
   216|  // Step 3: Write the complete merged set.
   217|  try {
   218|    await writeRenderEnvVars(
   219|      input.serviceId,
   220|      input.renderApiKey,
   221|      merged,
   222|      fetchImpl,
   223|    );
   224|  } catch (error) {
   225|    return {
   226|      traceId,
   227|      ok: false,
   228|      variablesBefore,
   229|      variablesAfter: existing.size,
   230|      added,
   231|      updated,
   232|      preserved,
   233|      missingAfterValidation: [],
   234|      rollbackInstructions: `Write failed. The existing ${variablesBefore} variables should be unchanged. Retry with the same updates.`,
   235|      error: error instanceof Error ? error.message : 'Unknown error during env-var write.',
   236|      secretValuesReturned: false,
   237|    };
   238|  }
   239|
   240|  // Step 4: Read again and validate.
   241|  let afterWrite: Map<string, string>;
   242|  try {
   243|    afterWrite = await readRenderEnvVars(
   244|      input.serviceId,
   245|      input.renderApiKey,
   246|      fetchImpl,
   247|    );
   248|  } catch (error) {
   249|    return {
   250|      traceId,
   251|      ok: false,
   252|      variablesBefore,
   253|      variablesAfter: merged.size,
   254|      added,
   255|      updated,
   256|      preserved,
   257|      missingAfterValidation: [],
   258|      rollbackInstructions: `Post-write validation read failed. ${merged.size} variables were written. Manually verify in Render dashboard. Rollback: re-PUT the original ${variablesBefore} variables.`,
   259|      error: error instanceof Error ? error.message : 'Unknown error during post-write validation.',
   260|      secretValuesReturned: false,
   261|    };
   262|  }
   263|
   264|  const variablesAfter = afterWrite.size;
   265|  const missingAfterValidation: string[] = [];
   266|
   267|  // Check required keys are present and non-empty.
   268|  for (const key of requiredKeys) {
   269|    const value = afterWrite.get(key);
   270|    if (!value || value.trim() === '') {
   271|      missingAfterValidation.push(key);
   272|    }
   273|  }
   274|
   275|  // Check preserved keys still exist (may have different values due to Render masking).
   276|  for (const key of preserved) {
   277|    if (!afterWrite.has(key)) {
   278|      missingAfterValidation.push(key);
   279|    }
   280|  }
   281|
   282|  if (missingAfterValidation.length > 0) {
   283|    return {
   284|      traceId,
   285|      ok: false,
   286|      variablesBefore,
   287|      variablesAfter,
   288|      added,
   289|      updated,
   290|      preserved,
   291|      missingAfterValidation,
   292|      rollbackInstructions: `Post-write validation detected missing variables: ${missingAfterValidation.join(', ')}. Rollback: re-PUT the original variable set saved in trace ${traceId}.`,
   293|      error: `Missing variables after write: ${missingAfterValidation.join(', ')}`,
   294|      secretValuesReturned: false,
   295|    };
   296|  }
   297|
   298|  return {
   299|    traceId,
   300|    ok: true,
   301|    variablesBefore,
   302|    variablesAfter,
   303|    added,
   304|    updated,
   305|    preserved,
   306|    missingAfterValidation: [],
   307|    rollbackInstructions: 'No rollback needed. All variables preserved.',
   308|    error: null,
   309|    secretValuesReturned: false,
   310|  };
   311|}
   312|
   313|/** Redact all secret values in a merge result for safe logging. */
   314|export function redactMergeResultForLogging(result: SafeMergeResult): Record<string, unknown> {
   315|  return {
   316|    traceId: result.traceId,
   317|    ok: result.ok,
   318|    variablesBefore: result.variablesBefore,
   319|    variablesAfter: result.variablesAfter,
   320|    added: result.added,
   321|    updated: result.updated,
   322|    preserved: result.preserved,
   323|    missingAfterValidation: result.missingAfterValidation,
   324|    error: result.error,
   325|    secretValuesReturned: false as const,
   326|  };
