     1|/**
     2| * Passwordless owner sign-in.
     3| *
     4| * POST /api/ivx/owner-passwordless-login
     5| *   body: { email }
     6| *
     7| * The owner types ONLY their email. The backend:
     8| *   1. Validates the email is in the owner allowlist
     9| *      (IVX_OWNER_REGISTRATION_EMAILS / IVX_BASELINE_OWNER_EMAILS).
    10| *   2. Uses the Supabase admin (service-role) client to find the owner auth user
    11| *      (creating + confirming them if they do not exist yet).
    12| *   3. Self-heals: sets the user's password to the configured
    13| *      IVX_OWNER_PASSWORD so the password grant always succeeds, even if the
    14| *      password drifted in Supabase. This is the fix for the recurring
    15| *      "invalid_credentials" block the owner hit.
    16| *   4. Performs a server-side password grant against Supabase Auth and returns
    17| *      the resulting session tokens (access_token, refresh_token, expires_at).
    18| *
    19| * The password is NEVER sent back to the client. The client installs the
    20| * returned session via supabase.auth.setSession(), which produces a real
    21| * Supabase session — so owner-AI chat approval (allowlist + bearer check)
    22| * works automatically.
    23| */
    24|import { randomBytes } from 'node:crypto';
    25|import { createClient, type SupabaseClient } from '@supabase/supabase-js';
    26|import { ownerOnlyJson, ownerOnlyOptions } from './owner-only';
    27|import { getIVXOwnerEmailAllowlist } from '../../expo/shared/ivx/access-control';
