    31|const PASSWORDLESS_HEADERS = {
    32|  'Content-Type': 'application/json',
    33|  'Cache-Control': 'no-store',
    34|  'Access-Control-Allow-Origin': 'https://ivxholding.com',
    35|  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    36|  'Access-Control-Allow-Methods': 'POST, OPTIONS',
