   116|/** Server-side password grant against the Supabase Auth token endpoint. */
   117|async function passwordGrant(supabaseUrl: string, email: string, password: string): Promise<{
   118|  ok: boolean;
   119|  accessToken?: string;
   120|  refreshToken?: string;
   121|  expiresAt?: number;
   122|  errorMessage?: string;
   123|  errorStatus?: number;
   124|}> {
   125|  const endpoint = `${supabaseUrl.replace(/\/+$/, '')}/auth/v1/token?grant_type=password`;
   126|  const anonKey = resolveAnonKey();
   127|  if (!anonKey) {
   128|    return { ok: false, errorMessage: 'Supabase anon key is not configured on the backend.' };
   129|  }
   130|  const controller = new AbortController();
   131|  const timer = setTimeout(() => controller.abort(), 20_000);
   132|  try {
   133|    const response = await fetch(endpoint, {
   134|      method: 'POST',
   135|      headers: {
   136|        'Content-Type': 'application/json',
   137|        apikey: anonKey,
   138|        Authorization: `Bearer ${anonKey}`,
   139|      },
   140|      body: JSON.stringify({ email, password }),
   141|      signal: controller.signal,
   142|    });
   143|    const text = await response.text();
   144|    let parsed: Record<string, unknown> = {};
   145|    try {
   146|      parsed = text ? (JSON.parse(text) as Record<string, unknown>) : {};
   147|    } catch {
   148|      return { ok: false, errorMessage: `Supabase returned non-JSON auth response (HTTP ${response.status}).` };
   149|    }
   150|    if (!response.ok) {
   151|      const message = typeof parsed.error_description === 'string'
   152|        ? parsed.error_description
   153|        : typeof parsed.msg === 'string'
   154|          ? parsed.msg
   155|          : typeof parsed.error === 'string'
   156|            ? parsed.error
   157|            : `Supabase rejected the password grant (HTTP ${response.status}).`;
   158|      return { ok: false, errorMessage: message, errorStatus: response.status };
   159|    }
   160|    const accessToken = typeof parsed.access_token === 'string' ? parsed.access_token : '';
   161|    const refreshToken = typeof parsed.refresh_token === 'string' ? parsed.refresh_token : '';
   162|    const expiresAt = typeof parsed.expires_at === 'number' ? parsed.expires_at : 0;
   163|    if (!accessToken || !refreshToken) {
   164|      return { ok: false, errorMessage: 'Supabase did not return access_token/refresh_token.' };
   165|    }
   166|    return { ok: true, accessToken, refreshToken, expiresAt };
   167|  } catch (error) {
   168|    return { ok: false, errorMessage: error instanceof Error ? error.message : 'Network failure during password grant.' };
   169|  } finally {
   170|    clearTimeout(timer);
   171|  }
   172|}
