    90|/** Map a thrown gateway error into a coarse class. */
    91|export function classifyProviderFailure(error: unknown): IVXProviderFailureClass {
    92|  if (!error) return 'unknown';
    93|  const name = error instanceof Error ? error.name : '';
    94|  const message = error instanceof Error ? error.message.toLowerCase() : String(error).toLowerCase();
    95|  const statusMatch = message.match(/status=(\d{3})/);
    96|  const status = statusMatch ? Number.parseInt(statusMatch[1], 10) : null;
