   105|    return 'rate_limit';
   106|  }
   107|  if (message.includes('insufficient_quota') || message.includes('quota')) {
   108|    return 'quota';
   109|  }
   110|  if (status && status >= 500) {
   111|    return 'server_error';
   112|  }
   113|  if (status === 400 || status === 422) {
